text:
{
  "formal_minutes": {
    "회의정보": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "confirmed_decisions": [
      {
        "category": "release_target",
        "decision": "공개 릴리스 목표 시점은 스모크 테스트 통과를 전제로 금요일 15:00 KST로 둔다.",
        "basis": "수요일 릴리스 제안에 대해 스모크 테스트 선행 필요 의견이 제기되었고, 최종 결정이 금요일 15:00 KST로 정리됨."
      },
      {
        "category": "package_name_mismatch_handling",
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다.",
        "basis": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하자는 제안은 거절되었음."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "수요일에 릴리스한다.",
        "result": "거절",
        "note": "수요일은 확정 일정이 아니라 내부 스트레치 목표로만 남음."
      },
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "result": "거절",
        "note": "불일치 발생 시 설정 확인이 우선이라는 방향으로 정리됨."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표",
        "note": "확정된 공개 릴리스 결정이 아님."
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계는 가능하면 목요일까지 검토",
        "note": "필요성은 언급되었으나 담당자가 지정되지 않음."
      },
      {
        "item": "Hara의 tarball 경로 확인",
        "note": "Minjun의 스모크 결과 공유 이후 수행 예정이나 정확한 기한은 정해지지 않음."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 릴리스가 지연될 수 있음."
      },
      {
        "risk": "README 설치 단계가 오래되었으면 릴리스 노트가 사용자에게 오해를 줄 수 있음."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "확정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시점",
      "status": "담당자 미지정",
      "source_certainty": "mentioned_but_unassigned"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과",
      "스모크 테스트 통과 여부에 따른 금요일 15:00 KST 공개 릴리스 가능성",
      "Doyun의 failure triage note 작성 완료 여부",
      "Hara의 tarball 경로 점검 결과",
      "README 설치 단계 최신성 검토 담당자 지정 여부",
      "최종 릴리스 승인 권한자 확인",
      "릴리스 노트에 내부 수요일 스트레치 목표를 언급할지 여부"
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "지정되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "인라인 공개 안전 synthetic fixture에 포함된 사실만 사용한다.",
    "확정 결정과 거절된 제안, 내부 스트레치 목표, 리스크, 오픈 질문을 분리한다.",
    "고객, 예산, 보안, 장애, 법무, 담당자, 마감일 관련 미기재 사실을 추가하지 않는다.",
    "담당자 미지정 항목은 미지정으로 유지하고 추정하지 않는다.",
    "정확한 시각 또는 조건이 없는 항목은 임의로 확정하지 않는다."
  ]
}
